// // This register outputs the previous value of d on every positive edge of clk when load is low.
module load_reg(clk, rst, load, d, q);

    input  clk;
    input  rst;
    input  load;
    input  [3:0] d;
    output reg [3:0] q;

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else if (load)
            q <= d;
    end

endmodule
